#include <stdio.h>
#include <stdlib.h>

int canEat(int *piles, int n, long long H, int K) {
    long long hours = 0;
    for (int i = 0; i < n; ++i) {
        hours += (piles[i] + K - 1) / K; // ceil division
        if (hours > H) return 0;
    }
    return 1;
}

int findMinK(int *piles, int n, long long H) {
    int low = 1, high = 0;
    for (int i = 0; i < n; ++i) if (piles[i] > high) high = piles[i];
    int ans = high;
    while (low <= high) {
        int mid = low + (high - low) / 2;
        if (canEat(piles, n, H, mid)) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }
    return ans;
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N;
        long long H;
        scanf("%d %lld", &N, &H);
        int *piles = (int *)malloc(N * sizeof(int));
        for (int i = 0; i < N; ++i) scanf("%d", &piles[i]);
        printf("%d\n", findMinK(piles, N, H));
        free(piles);
    }
    return 0;
}

