import sys

def canEat(piles, H, K):
    hours = 0
    for p in piles:
        hours += (p + K - 1) // K  # ceil division
        if hours > H:
            return False
    return True

def findMinK(piles, H):
    low, high = 1, max(piles)
    ans = high
    while low <= high:
        mid = (low + high) // 2
        if canEat(piles, H, mid):
            ans = mid
            high = mid - 1
        else:
            low = mid + 1
    return ans

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it)); H = int(next(it))
        piles = [int(next(it)) for _ in range(N)]
        out_lines.append(str(findMinK(piles, H)))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    main()

